from zeep import Client
from zeep.exceptions import Fault

# Function to get policy details
def get_policy_details(policy_number, customer_name):
    # Initialize SOAP client
    client = Client('https://thirdpartyinsurance.com/soap?wsdl')
    
    # Prepare request parameters
    request_payload = {
        'PolicyNumber': policy_number,
        'CustomerName': customer_name
    }

    try:
        # Send request to the SOAP service
        response = client.service.GetPolicyDetails(**request_payload)
        return response
    except Fault as fault:
        return f"Error: {fault}"

